import 'dart:async';import 'dart:convert';import 'package:flutter/material.dart';import 'package:http/http.dart' as http;import 'reset_password_page.dart';import 'app_text.dart';class OTPPage extends StatefulWidget {  final String email;  const OTPPage({super.key, required this.email});  @override  State<OTPPage> createState() => _OTPPageState();}class _OTPPageState extends State<OTPPage> {  final TextEditingController _otpCtrl = TextEditingController();  bool loading = false;  static const String backendBase = "http://192.168.1.6:4000";  int seconds = 30;  bool canResend = false;  Timer? timer;  @override  void initState() {    super.initState();    startTimer();  }  @override  void dispose() {    _otpCtrl.dispose();    timer?.cancel();    super.dispose();  }  /* ================= TIMER ================= */  void startTimer() {    seconds = 30;    canResend = false;    timer = Timer.periodic(const Duration(seconds: 1), (t) {      if (seconds == 0) {        t.cancel();        setState(() {          canResend = true;        });      } else {        setState(() {          seconds--;        });      }    });  }  /* ================= VERIFY ================= */  Future<void> verifyOTP() async {    if (_otpCtrl.text.trim().isEmpty) {      _toast(AppText.t("enterOtp"));      return;    }    setState(() => loading = true);    try {      final res = await http.post(        Uri.parse("$backendBase/api/auth/verify-otp"),        headers: {"Content-Type": "application/json"},        body: jsonEncode({          "email": widget.email,          "otp": _otpCtrl.text.trim(),        }),      );      final data = jsonDecode(res.body);      if (!mounted) return;      if (res.statusCode == 200) {        Navigator.pushReplacement(          context,          MaterialPageRoute(            builder: (_) => ResetPasswordPage(email: widget.email),          ),        );      } else {        _toast(data["msg"] ?? AppText.t("invalidOtp"));      }    } catch (_) {      _toast(AppText.t("networkError"));    }    if (mounted) setState(() => loading = false);  }  /* ================= RESEND ================= */  Future<void> resendOTP() async {    if (!canResend) return;    try {      final res = await http.post(        Uri.parse("$backendBase/api/auth/forgot-password"),        headers: {"Content-Type": "application/json"},        body: jsonEncode({          "email": widget.email        }),      );      if (res.statusCode == 200) {        _toast(AppText.t("otpSentAgain"));        startTimer();      } else {        _toast(AppText.t("otpFailed"));      }    } catch (_) {      _toast(AppText.t("networkError"));    }  }  void _toast(String msg) {    ScaffoldMessenger.of(context)        .showSnackBar(SnackBar(content: Text(msg)));  }  /* ================= UI ================= */  @override  Widget build(BuildContext context) {    return Scaffold(      backgroundColor: Colors.white,      appBar: AppBar(        elevation: 0,        backgroundColor: Colors.white,        foregroundColor: Colors.black,        title: Text(          AppText.t("verifyOtp"),          style: const TextStyle(fontWeight: FontWeight.w600),        ),      ),      body: Center(        child: SingleChildScrollView(          padding: const EdgeInsets.all(24),          child: _card(            child: Column(              mainAxisSize: MainAxisSize.min,              children: [                const Icon(                  Icons.security,                  size: 64,                  color: Colors.green,                ),                const SizedBox(height: 16),                Text(                  AppText.t("otpVerification"),                  style: const TextStyle(                    fontSize: 18,                    fontWeight: FontWeight.bold,                  ),                ),                const SizedBox(height: 6),                Text(                  AppText.t("enterOtpSent"),                  style: const TextStyle(color: Colors.black54),                ),                const SizedBox(height: 4),                Text(                  widget.email,                  style: const TextStyle(                    color: Colors.green,                    fontWeight: FontWeight.w600,                  ),                  textAlign: TextAlign.center,                ),                const SizedBox(height: 24),                _otpField(),                const SizedBox(height: 12),                canResend                    ? TextButton(                  onPressed: resendOTP,                  child: Text(AppText.t("resendOtp")),                )                    : Text(                  "${AppText.t("resendIn")} $seconds s",                  style: const TextStyle(color: Colors.grey),                ),                const SizedBox(height: 20),                _verifyButton(),              ],            ),          ),        ),      ),    );  }  /* ================= WIDGETS ================= */  Widget _card({required Widget child}) {    return Container(      padding: const EdgeInsets.all(24),      decoration: BoxDecoration(        color: Colors.white,        borderRadius: BorderRadius.circular(16),        boxShadow: const [          BoxShadow(            color: Color(0x22000000),            blurRadius: 10,            offset: Offset(0, 4),          ),        ],      ),      child: child,    );  }  Widget _otpField() {    return TextField(      controller: _otpCtrl,      keyboardType: TextInputType.number,      textAlign: TextAlign.center,      maxLength: 6,      style: const TextStyle(        fontSize: 22,        letterSpacing: 6,        fontWeight: FontWeight.bold,      ),      decoration: InputDecoration(        counterText: "",        hintText: "••••••",        hintStyle: const TextStyle(color: Colors.black38),        filled: true,        fillColor: Colors.grey.shade100,        border: OutlineInputBorder(          borderRadius: BorderRadius.circular(14),          borderSide: BorderSide.none,        ),      ),    );  }  Widget _verifyButton() {    return SizedBox(      width: double.infinity,      child: ElevatedButton(        onPressed: loading ? null : verifyOTP,        style: ElevatedButton.styleFrom(          backgroundColor: Colors.green,          foregroundColor: Colors.white,          padding: const EdgeInsets.symmetric(vertical: 14),          shape: RoundedRectangleBorder(            borderRadius: BorderRadius.circular(14),          ),        ),        child: loading            ? const SizedBox(          height: 22,          width: 22,          child: CircularProgressIndicator(            color: Colors.white,            strokeWidth: 2,          ),        )            : Text(          AppText.t("verifyOtp").toUpperCase(),          style: const TextStyle(            fontSize: 15,            fontWeight: FontWeight.w600,            letterSpacing: 1,          ),        ),      ),    );  }}